patch:
--- a/comparator.v
+++ b/comparator.v
@@ -1,5 +1,5 @@
 module compare_4(
   input [3:0] a, b,
-  output eq, gt, lt, extra_port
+  output eq, gt, lt
 );
   assign eq = (a == b);
   assign gt = (a > b);
@@ -11,5 +11,5 @@ module top_cmp(
   input [3:0] x, y,
   output eq_out, gt_out, lt_out
 );
-  compare_4 cmp(.a(x), .b(y), .eq(eq_out), .gt(gt_out), .lt(lt_out), .extra_port());
+  compare_4 cmp(.a(x), .b(y), .eq(eq_out), .gt(gt_out), .lt(lt_out));
 endmodule

before_code:
module compare_4(
  input [3:0] a, b,
  output eq, gt, lt, extra_port
);
  assign eq = (a == b);
  assign gt = (a > b);
  assign lt = (a < b);
endmodule

module top_cmp(
  input [3:0] x, y,
  output eq_out, gt_out, lt_out
);
  compare_4 cmp(.a(x), .b(y), .eq(eq_out), .gt(gt_out), .lt(lt_out), .extra_port());
endmodule

after_code:
module compare_4(
  input [3:0] a, b,
  output eq, gt, lt
);
  assign eq = (a == b);
  assign gt = (a > b);
  assign lt = (a < b);
endmodule

module top_cmp(
  input [3:0] x, y,
  output eq_out, gt_out, lt_out
);
  compare_4 cmp(.a(x), .b(y), .eq(eq_out), .gt(gt_out), .lt(lt_out));
endmodule
